package target

import (
	"net/http"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
)

// RegisterRoutes registers the routes for the target service, which receives
// the requests generated by the load runner.
func RegisterRoutes(router *gin.Engine) {
	router.GET("/target/ping", handlePing)
}

// handlePing responds to load test requests.
//
// It accepts an optional `delay_ms` query parameter that introduces an
// artificial delay, allowing latency, SLO, and alerting scenarios to be
// simulated during observability experiments.
//
//	@Summary	Target endpoint for load testing
//	@Tags		target
//	@Produce	json
//	@Param		delay_ms	query		int	false	"Artificial delay in milliseconds"
//	@Success	200			{object}	map[string]bool
//	@Router		/target/ping [get]
func handlePing(c *gin.Context) {
	if delayParam := c.Query("delay_ms"); delayParam != "" {
		if delayMs, err := strconv.Atoi(delayParam); err == nil && delayMs > 0 {
			time.Sleep(time.Duration(delayMs) * time.Millisecond)
		}
	}

	c.JSON(http.StatusOK, gin.H{"pong": true})
}
